INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ed9d11e6-588c-4421-9d28-ebceb4bd72ee',
  '00000000-0000-0000-0000-000000000001',
  $escape$gdscript Modding Support: Exposing APIs to Lua with GDNative$escape$,
  $escape$To add modding support to your gdscript project, you can use GDNative to expose APIs to Lua. This allows community creators to extend your game's functionality without modifying the core code. First, create a GDNative library that wraps your gdscript API. Then, use the Lua bindings to call your API from Lua scripts. This approach provides a sandboxed environment for scripting, ensuring that mods cannot access sensitive game data. By exposing your API to Lua, you can enable a wide range of community-created content, from simple scripts to complex mods.$escape$,
  $escape$extends Node
func _ready():
    var lua = LuaState.new()
    lua.open_libraries()
    lua.do_string("print('Hello from Lua')")$escape$,
  $escape$gdscript$escape$,
