INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ce523e2a-b952-4a92-a751-02a6e22c11df',
  '00000000-0000-0000-0000-000000000001',
  $escape$gdscript — Unleashing Data-Oriented Design with Structs of Arrays$escape$,
  $escape$In gdscript, Data-Oriented Design (DOD) is achieved by storing data in a Struct of Arrays (SoA) pattern. This pattern involves grouping related data into structs and storing multiple instances of these structs in an array. For example, a `Transform` struct can hold position, rotation, and scale data, while an array of `Transform` can store the state of multiple game objects.$escape$,
  $escape$enum Axis { X, Y, Z } 
struct Transform {
    var position = Vector3.ZERO 
    var rotation = Vector3.ZERO 
    var scale = Vector3.ONE
}
class GameObject {
    var transform = Transform.new()$escape$,
  $escape$gdscript$escape$,
