INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '827bb095-7ee9-4309-a7cc-7e4ed5f657fa',
  '00000000-0000-0000-0000-000000000001',
  $escape$gdscript: Bridging C# and GDNative for Efficient Game Development$escape$,
  $escape$When working on a Unity project with GDScript, you often need to integrate C# and native plugins. Similarly, in Unreal Engine, you might want to leverage C++ and Blueprint. However, using GDScript's built-in FFI (Foreign Function Interface) allows you to interface with C# and C++ code seamlessly. To call a C# function from GDScript, you can use the FFI's `new` function, which returns an instance of a C# class.$escape$,
  $escape$extends KinematicBody2D
var player = FFI.new('PlayerClass')
player.jump()$escape$,
  $escape$gdscript$escape$,
